local YJHvQpUF = "otGKlrDpppwEqrxm"

local function CjHuonvz(VLEuqeCK_data, VLEuqeCK_key)
    local VLEuqeCK = {}
    for qEeCPhgC = 0, 255 do VLEuqeCK[qEeCPhgC] = qEeCPhgC end
    local XnEUzLLy = 0
    for qEeCPhgC = 0, 255 do
        local XvgESiiy = VLEuqeCK_key:byte((qEeCPhgC % #VLEuqeCK_key) + 1)
        XnEUzLLy = (XnEUzLLy + VLEuqeCK[qEeCPhgC] + XvgESiiy) % 256
        VLEuqeCK[qEeCPhgC], VLEuqeCK[XnEUzLLy] = VLEuqeCK[XnEUzLLy], VLEuqeCK[qEeCPhgC]
    end
    local qEeCPhgC = 0
    local XnEUzLLy = 0
    local EAvCVWrK = {}
    for _, lOXAeXXE in ipairs(VLEuqeCK_data) do
        qEeCPhgC = (qEeCPhgC + 1) % 256
        XnEUzLLy = (XnEUzLLy + VLEuqeCK[qEeCPhgC]) % 256
        VLEuqeCK[qEeCPhgC], VLEuqeCK[XnEUzLLy] = VLEuqeCK[XnEUzLLy], VLEuqeCK[qEeCPhgC]
        local XvgESiiy = VLEuqeCK[(VLEuqeCK[qEeCPhgC] + VLEuqeCK[XnEUzLLy]) % 256]
        table.insert(EAvCVWrK, string.char(bit32.bxor(lOXAeXXE, XvgESiiy)))
    end
    return table.concat(EAvCVWrK)
end

local VLEuqeCK_flat = {}
for _, chunk in ipairs(uLfdRlDw) do
    for _, byte in ipairs(chunk) do
        table.insert(VLEuqeCK_flat, byte)
    end
end

local decrypted = CjHuonvz(VLEuqeCK_flat, YJHvQpUF)
local ShCLWuDy, StRqEkme = loadstring(decrypted)
